void main() {
  var words = ['apple', 'banana', 'cherry', 'date', 'elderberry'];

  var longWords = words
      .where((w) => w.length > 5)
      .map((w) => w.toUpperCase())
      .toList();

  print('Long words: $longWords');

  var firstLong = words.firstWhere(
    (w) => w.length > 5,
    orElse: () => 'NONE',
  );

  var totalChars = words.fold(0, (sum, w) => sum + w.length);
  print('Total characters: $totalChars');
  print('First long: $firstLong');

  var hasShort = words.any((w) => w.length < 4);
  print('Has short word: $hasShort');
}
